CODE_EXAMPLE:
// Before
class Person {}
class Male extends Person {
  String getCode() { return "M"; }
}
class Female extends Person {
  String getCode() { return "F"; }
}

// After
class Person {
  static final int MALE = 0;
  static final int FEMALE = 1;
  private int type;

  static Person createMale() {
    return new Person(MALE);
  }

  String getCode() {
    return (type == MALE) ? "M" : "F";
  }
}

UNIT_TEST_EXAMPLE:
@Test
public void testSubclassWithFields() {
  Person male = Person.createMale();
  assertEquals("M", male.getCode());
}
